//images.unsplash.com/photo-1526779259212-939e64788e3c?auto=format&fit=crop&w=1400&q=80",href:"/attractions/fuzuli-gateway"},{title:"Regional road connections",desc:"Follow the main routes linking Fuzuli to Shusha, Aghdam, and other Karabakh destinations.",img:"https://images.unsplash.com/photo-1501785888041-af3ef285b470?auto=format&fit=crop&w=1400&q=80",href:"/attractions/fuzuli-routes"},{title:"Open plains viewpoints",desc:"Experience wide horizons and flatland scenery that contrast with Karabakh’s mountain regions.",img:"https://images.unsplash.com/photo-1470770841072-f978cf4d019e?auto=format&fit=crop&w=1400&q=80",href:"/attractions/fuzuli-plains"},{title:"Development zones",desc:"Observe new infrastructure, planning projects, and the region’s rebuilding direction.",img:"https://images.unsplash.com/photo-1489515217757-5fd1be406fef?auto=format&fit=crop&w=1400&q=80",href:"/attractions/fuzuli-development"}],things:{title:"Explore the gateway role of Fuzuli",subtitle:"Choose how to experience the region from its main entry point.",categories:[{slug:"arrival",title:"Arrival & logistics",teaser:"Starting point for your trip.",img:"https://images.unsplash.com/photo-1526779259212-939e64788e3c?auto=format&fit=crop&w=1400&q=80",panel:{headline:"Begin your journey",body:"Understand arrival routes, transport options, and how to plan your movement into the wider Karabakh region.",ctaText:"Plan arrival",ctaHref:"/things/fuzuli/arrival",tiles:[{title:"Arrival Guide",img:"https://images.unsplash.com/photo-1526779259212-939e64788e3c?auto=format&fit=crop&w=1200&q=80",href:"/things/fuzuli/arrival-guide"},{title:"Transport Options",img:"https://images.unsplash.com/photo-1501785888041-af3ef285b470?auto=format&fit=crop&w=1200&q=80",href:"/things/fuzuli/transport"}]}},{slug:"routes",title:"Regional routes",teaser:"Road connections across Karabakh.",img:"https://images.unsplash.com/photo-1501785888041-af3ef285b470?auto=format&fit=crop&w=1400&q=80",panel:{headline:"Route planning",body:"